// Səhər yeməyi siyahısı
let breakfastList = ["yumurta", "süd", "çörək", "pendir"];
console.log(breakfastList); // nəticə: ["yumurta", "süd", "çörək", "pendir"]
console.log(breakfastList[0]); // nəticə: yumurta
console.log(breakfastList.length); // nəticə: 4

// Array-ə element əlavə etmək və dəyişdirmək
let breakfastList = ["yumurta", "süd"];
breakfastList.push("çörək"); // sona əlavə edir
console.log(breakfastList); // nəticə: ["yumurta", "süd", "çörək"]
breakfastList[1] = "qatıq"; // 1-ci indeksi dəyişdirir
console.log(breakfastList); // nəticə: ["yumurta", "qatıq", "çörək"]

// Array vs Obyekt
let breakfastList = ["yumurta", "süd", "çörək"];
let breakfastObject = { item1: "yumurta", item2: "süd", item3: "çörək" };
console.log(breakfastList[0]); // nəticə: yumurta
console.log(breakfastObject.item1); // nəticə: yumurta

// Array-də təkrar
breakfastList.push("yumurta");
console.log(breakfastList); // nəticə: ["yumurta", "süd", "çörək", "yumurta"]

// İndeks səhvi nümunəsi
let breakfastList = ["yumurta", "süd"];
console.log(breakfastList[5]); // nəticə: undefined

// Təkrar əlavə
breakfastList.push("yumurta");
console.log(breakfastList); // nəticə: ["yumurta", "süd", "yumurta"]

