// Breakfast shopping list
let breakfastList = ["eggs", "milk", "bread", "cheese"];
console.log(breakfastList); // Output: ["eggs", "milk", "bread", "cheese"]
console.log(breakfastList[0]); // Output: eggs
console.log(breakfastList.length); // Output: 4

// Adding and changing array elements
let breakfastList = ["eggs", "milk"];
breakfastList.push("bread"); // Adds to the end
console.log(breakfastList); // Output: ["eggs", "milk", "bread"]
breakfastList[1] = "yogurt"; // Changes index 1
console.log(breakfastList); // Output: ["eggs", "yogurt", "bread"]

// Array vs Object
let breakfastList = ["eggs", "milk", "bread"];
let breakfastObject = { item1: "eggs", item2: "milk", item3: "bread" };
console.log(breakfastList[0]); // Output: eggs
console.log(breakfastObject.item1); // Output: eggs

// Duplicates in array
breakfastList.push("eggs");
console.log(breakfastList); // Output: ["eggs", "milk", "bread", "eggs"]

// Index error example
let breakfastList = ["eggs", "milk"];
console.log(breakfastList[5]); // Output: undefined

// Adding duplicates
breakfastList.push("eggs");
console.log(breakfastList); // Output: ["eggs", "milk", "eggs"]

