content.code:
// Список покупок для завтрака
let breakfastList = ["яйца", "молоко", "хлеб", "сыр"];
console.log(breakfastList); // Вывод: ["яйца", "молоко", "хлеб", "сыр"]
console.log(breakfastList[0]); // Вывод: яйца
console.log(breakfastList.length); // Вывод: 4

// Добавление и изменение элементов массива
let breakfastList = ["яйца", "молоко"];
breakfastList.push("хлеб"); // Добавляет в конец
console.log(breakfastList); // Вывод: ["яйца", "молоко", "хлеб"]
breakfastList[1] = "йогурт"; // Изменяет элемент на индексе 1
console.log(breakfastList); // Вывод: ["яйца", "йогурт", "хлеб"]

// Массив vs Объект
let breakfastList = ["яйца", "молоко", "хлеб"];
let breakfastObject = { item1: "яйца", item2: "молоко", item3: "хлеб" };
console.log(breakfastList[0]); // Вывод: яйца
console.log(breakfastObject.item1); // Вывод: яйца

// Дубликаты в массиве
breakfastList.push("яйца");
console.log(breakfastList); // Вывод: ["яйца", "молоко", "хлеб", "яйца"]

// Пример ошибки индекса
let breakfastList = ["яйца", "молоко"];
console.log(breakfastList[5]); // Вывод: undefined

// Добавление дубликатов
breakfastList.push("яйца");
console.log(breakfastList); // Вывод: ["яйца", "молоко", "яйца"]

